"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[95],{7095:function(e,t,a){a.d(t,{$r:function(){return i}});let i=[{id:"claude-code-runtime",label:"Claude Code Runtime",emoji:"\uD83D\uDEE0️",tagline:"Boot → query loop → tools → permissions → MCP → tasks → UI",defaultSelectedId:"ccr-query",nodes:[{id:"ccr-boot",title:"Boot + Session Assembly",tooltip:"main.tsx — 6-step runtime assembly before the first prompt",description:"Normalizes CLI args, loads enterprise/user/project settings, resolves trust, selects model, assembles tool registry, connects MCP servers, restores transcript (on resume), fires deferred prefetch, then routes to one of five session modes: interactive REPL, non-interactive (-p), remote, coordinator, or assistant (KAIROS). Startup timeline: T+0ms stdin buffered (keystrokes during boot are not lost); T+2ms `startMdmRawRead()` and `startKeychainPrefetch()` fire between import statements, overlapping with module evaluation; T+137ms module evaluation completes (MDM and keychain reads already done); T+150ms API preconnection HEAD request fires, placing a TCP+TLS connection into Bun's keep-alive pool before the first model call.",rationale:"Everything downstream assumes the session is fully assembled. main.tsx ensures that invariant before query.ts ever runs. The mode fork is also here — interactive vs non-interactive vs CCR vs coordinator all diverge at this point, not later. Side-effect hoisting (MDM + keychain between imports) and the API preconnect save 100–200ms of perceived latency on the first real model call.",insight:{label:"Source anchor",body:"`src/cli.tsx` + `src/main.tsx` + `src/interactiveHelpers.tsx`. `cli.tsx` is the real entry point: `--version` returns with zero module loads; subcommands load only what they need. Startup shows 6 onboarding dialogs on first run (theme, trust, MCP approval, CLAUDE.md includes, bypass-permissions, auto-mode opt-in). `showSetupScreens()` in interactiveHelpers owns that pipeline. SYSTEM_PROMPT_DYNAMIC_BOUNDARY is a sentinel string splitting the system prompt into a cached static prefix and an uncached dynamic suffix — changing anything below the boundary does not invalidate the prompt cache."},tradeoffs:"A rich assembly phase keeps the turn loop clean at the cost of startup latency. Every new session-scoped feature (voice, bridge, ultraplan) needs a hook here. Side-effect hoisting keeps latency low at the cost of making boot order sensitive to import order.",alternatives:'Lazy capability loading would reduce startup time but breaks the "session ready" contract that lets downstream code assume a stable capability surface.',x:580,y:44,width:310,height:92},{id:"ccr-input",title:"Input Router",tooltip:"processUserInput — routes text | !bash | /slash to correct handler",description:"Normalizes every user keystroke into one of three paths: text prompt (processTextPrompt), bash shorthand via `!cmd` (processBashCommand → BashTool/PowerShellTool), or slash command (processSlashCommand → command handler / forked sub-agent). Also extracts image attachments, handles `@agent` mentions, detects ultraplan keyword early, runs UserPromptSubmit hooks, and enforces 10 000-char truncation.",rationale:"Centralizing input routing here keeps query.ts clean and allows each path (text, bash, slash) to apply its own normalization without polluting the turn loop. The isMeta flag lets background scheduler messages be invisible to the user but visible to the model.",insight:{label:"Source anchor",body:"`src/utils/processUserInput/processUserInput.ts` (606 lines). Ultraplan keyword detection happens before slash-command routing. PowerShellTool is a 300KB lazy-loaded chunk that only loads on Windows or when needed. `speculativeExecute.ts` (`src/utils/speculation/`) forks a query turn preemptively when the user pauses typing — if the user submits the same prompt, the fork is promoted (saving one full model round-trip). If input diverges, the fork is tombstoned. Speculative turns run against a shadow overlay directory: accepted writes propagate to the main tree, abandoned forks discard without side effects."},tradeoffs:"One function owning three very different paths can accumulate complexity. The bridge-safe override pattern (CCR clients skip slash commands unless isBridgeSafeCommand) adds another conditional dimension.",alternatives:"Splitting into three separate entry points would be cleaner but would duplicate attachment extraction, hook execution, and ultraplan detection across all three.",x:44,y:210,width:280,height:92},{id:"ccr-cmd",title:"Command System",tooltip:"commands.ts — 6-source slash command assembly",description:"Assembles slash commands from 6 sources: built-in, user skills, plugin-injected, project-scoped, MCP-derived prompts, and runtime dynamic skills. `loadAllCommands()` is memoized per cwd. `getCommands()` re-filters every call using `meetsAvailabilityRequirement()`. REMOTE_SAFE and BRIDGE_SAFE allowlists gate which commands run in CCR sessions.",rationale:"Commands are a product affordance layer separate from tool calls. The fresh-filter pattern (getCommands vs loadAllCommands) means availability state (session mode, permission mode, feature flags) is always checked at call time without re-loading definitions.",insight:{label:"Source anchor",body:"`src/commands.ts`. 100+ command directories under `src/commands/**`. Key availability gates: `immediate: true` = no model round-trip; `type: local-jsx` = React-rendered UI; skill insertion position (SKILLS_START) separates dynamic from static commands."},tradeoffs:"A 6-source merge is flexible but makes the active command set session-dependent. The REMOTE_SAFE/BRIDGE_SAFE split is the main policy lever to prevent unsafe operations in remote-control sessions.",alternatives:"Collapsing commands into prompt instructions would lose structured routing, availability gating, and the ability to surface commands as UI affordances.",x:360,y:210,width:280,height:92},{id:"ccr-query",title:"Query Loop",tooltip:"query.ts — recoverable AsyncGenerator turn loop with 7 named recovery conditions",description:"The execution center. Manages mutable `State` (messages, turns, toolUseID, compact, transition) as an AsyncGenerator. Handles seven named recovery conditions: fallback-model retry, compaction circuit breaker, max_output_tokens continuation, prompt-too-long reactive compact, stop hook resume, tool-use-only continuation, and post-compact continuation. Runs a five-step preprocessing pipeline before every model call: budget → snip → microcompact → context collapse → autocompact (ordering is load-bearing; each step can short-circuit the next). Hands tool batches to services/tools rather than executing inline.",rationale:"A single turn often requires multiple model sampling rounds. query.ts models the full turn lifecycle as a recoverable state machine, not a single API call, with `State.transition` recording exactly which recovery condition fired — making recovery paths testable without inspecting message content.",insight:{label:"Source anchor",body:"`src/query.ts`. `QueryDeps` has exactly four method signatures — `callModel`, `compact`, `uuid`, `now` — making it a minimal test seam for the loop. The five-step preprocessing pipeline ordering is not arbitrary: budget must run before snip, snip before microcompact, and so on. `query/tokenBudget.ts` manages budget. `query/stopHooks.ts` runs PostQuery hooks. autoCompact circuit breaker: when `State.compactFailed = true` (previous compaction failed), the preprocessing pipeline skips autoCompact on the current turn to prevent retry storms when the summarization model fails."},tradeoffs:"A stateful loop is harder to trace but handles streaming, compaction, fallback, and tool-use continuation without outside help. The State.transition field is essential for debugging which recovery condition fired.",alternatives:"A stateless per-turn API call is simpler to host but cannot handle multi-round tool use, context compaction, or streaming fallback without moving that logic outside the product.",x:676,y:210,width:280,height:92},{id:"ccr-auth",title:"Auth + OAuth",tooltip:"services/oauth — PKCE flow, token lifecycle, policy limits",description:"Full OAuth 2.0 PKCE flow with dual-mode support (browser redirect or manual paste). Manages token refresh, profile caching, subscription type detection (max/pro/enterprise/team), and organization UUID resolution. PolicyLimits service adds org-level feature restrictions (fail-open, 1hr background polling, ETag revalidation). SettingsSync pushes user settings and CLAUDE.md to cloud between devices.",rationale:'Authentication is not just "is the user logged in." The OAuth service determines which session modes are available (bridge requires claude.ai OAuth, not API keys), what subscription features are unlocked, and which policy restrictions apply. SettingsSync and PolicyLimits both depend on OAuth scope.',insight:{label:"Source anchor",body:"`src/services/oauth/**`. Bridge requires full-scope OAuth (profile scope). PolicyLimits at `src/services/policyLimits/index.ts` — checks `isPolicyAllowed()` before bridge init. HIPAA exception: `allow_product_feedback` defaults deny on cache miss."},tradeoffs:"Fail-open policy limits is the right default for network failures (restricting features on a flaky connection would harm users), but HIPAA-sensitive policies (product feedback) default deny on cache miss.",alternatives:"API-key-only auth is simpler but loses bridge/remote control, subscription gating, and cross-device settings sync.",x:992,y:210,width:280,height:92},{id:"ccr-tool-proto",title:"Tool Protocol + Registry",tooltip:"Tool.ts + tools.ts — 20+ property interface, fail-closed defaults",description:"25+ built-in tools organized into 7 categories: file (Read/Edit/Write/Glob/Grep/Notebook), shell (Bash/PowerShell/REPL), search+external (WebFetch/WebSearch/LSP), workflow (TodoWrite/Cron/Sleep/Config), communication (SendMessage/Brief), agent (AgentTool/Skill/TeamCreate), and MCP surface (ListMcpResources/ReadMcpResource/McpAuth). `buildTool()` fills fail-closed defaults: `isConcurrencySafe→false`, `isReadOnly→false`.",rationale:"The tool interface is a runtime protocol covering execution, governance (permissions, concurrency), and UI hints. `buildTool()` defaults fail-closed so a new tool author cannot accidentally allow parallel writes or skip classifier evaluation.",insight:{label:"Source anchor",body:'`src/Tool.ts` and `src/tools.ts`. Key concurrency facts: FileRead, Glob, Grep, WebFetch, WebSearch, LSP, CronList, SleepTool all return `isConcurrencySafe: true`. BashTool readonly is input-dependent (checks if the command writes). `toAutoClassifierInput()` returns "" by default — tools must opt-in to auto-mode classifier. BashTool five defense layers (first deny wins): (1) tree-sitter AST static analysis — write/exec/network flags; unparseable input = fail-closed; (2) `readOnlyValidation.ts` — syscall-intent read-only check; (3) path safety — blocks writes to `.git/`, `.env`, shell configs; (4) destructive command warning — `rm -rf`, `dd`, `mkfs`, format-class commands prompt before execution even in bypass mode; (5) sandbox routing — wraps via `@anthropic-ai/sandbox-runtime` when sandbox is active. FileReadTool blocks device file reads. AgentTool enforces a nesting depth limit to prevent unbounded agent recursion.'},tradeoffs:"A 20+ property interface makes permission engine, streaming executor, and UI all work generically. The cost is that every new tool must define its governance hints explicitly.",alternatives:"A minimal function registry (name → async fn) is easier to build but pushes permission, concurrency, and UI logic into call sites.",x:44,y:390,width:280,height:92},{id:"ccr-perms",title:"Permission Engine + Sandbox",tooltip:"permissions.ts + sandbox-adapter.ts — 7-step decisions + execution isolation",description:'Two-layer execution gate: (1) Permission Engine runs a 7-step decision tree (deny rule, ask rule, tool.checkPermissions, 4 sub-steps including filesystem safety checks at 1e–1g that are bypass-immune, bypass mode, allow rule, passthrough→ask). Auto-mode step: `autoHandler.ts` uses tree-sitter AST to classify bash commands statically — write/exec/network patterns are flagged without executing the command. Tools not opted into `toAutoClassifierInput()` return `""` and skip classifier evaluation, falling through to interactive mode. (2) Sandbox System wraps `@anthropic-ai/sandbox-runtime` with filesystem read/write restrictions, network access controls, and dependency checks (ripgrep, bwrap, socat, seccomp). Sandbox is a distinct layer executed after permission approval.',rationale:"Permission gating and execution sandboxing solve different problems. Permission engine decides whether an action is authorized. Sandbox constrains what a permitted action can actually access or affect. Safety check steps 1e–1g (`.git/`, `.claude/`, shell configs) run before bypass mode — they are the only bypass-immune gates.",insight:{label:"Source anchor",body:"`src/utils/permissions/permissions.ts` + `src/utils/sandbox/sandbox-adapter.ts`. `SandboxManager` wraps `@anthropic-ai/sandbox-runtime`. `/sandbox` command (`src/commands/sandbox-toggle/`) shows multi-tab settings UI. Linux requires bwrap; macOS uses seccomp. `autoHandler.ts` (`src/hooks/toolPermission/handlers/autoHandler.ts`) — tree-sitter AST analysis for bash auto-classification in auto-mode. `interactiveHandler.ts` manages the interactive approval dialog and suspend/resume of the blocked tool call."},tradeoffs:"Separating permission from sandbox lets them evolve independently. Enterprise customers can lock sandbox settings via policy. The dual-layer means safe work can proceed automatically while shell commands still get execution-isolation.",alternatives:"A single flat allow/deny list is easier to audit statically but cannot express rule precedence, content-based decisions, or isolation levels.",x:360,y:390,width:280,height:92},{id:"ccr-mcp",title:"MCP Assembly",tooltip:"services/mcp — 7-source config, content-based dedup, 3-surface expansion",description:"Staged pipeline: load server definitions from 7 sources (enterprise, plugin, user, project, local, dynamic, claude.ai), apply precedence + plugin-only locks + enterprise exclusivity, deduplicate by `getMcpServerSignature()` (stdio command+args or normalized URL — not config key names), connect with transport-specific logic, then expand each server into runtime Tool objects, Command objects, and Resource entries. `getClaudeCodeMcpConfigs()` is fast/local; `getAllMcpConfigs()` waits for claude.ai connector discovery.",rationale:"Content-based dedup catches real-world cases: a plugin config and a manual config launching the same process, or a proxy URL and a raw vendor URL reaching the same backend. Name-based dedup would miss these.",insight:{label:"Source anchor",body:"`src/services/mcp/config.ts` + `src/services/mcp/client.ts`. Three discovery functions: `fetchToolsForClient()`, `fetchCommandsForClient()`, `fetchResourcesForClient()`. `connectToServer()` handles stdio, SSE, and HTTP transports with auth wrappers and retry."},tradeoffs:"The fast/slow config path split allows startup to show a baseline capability surface before cloud-backed connectors are ready. The cost is that `getAllMcpConfigs()` callers may see a different set than `getClaudeCodeMcpConfigs()` callers.",alternatives:"Treating MCP as a connector plugin bolted onto tools.ts would be simpler but would lose governance (policy filtering, deduplication) and the 3-surface expansion into tools, commands, and resources.",x:676,y:390,width:280,height:92},{id:"ccr-lsp",title:"LSP Integration",tooltip:"services/lsp + LSPTool — multi-server code intelligence",description:"Multi-server LSP stack: `LSPServerInstance` (factory pattern, state machine with 5 states, exponential backoff retry for -32801 transient errors, crash recovery counter), `LSPClient` (JSON-RPC via vscode-jsonrpc, lazy-loaded ~129KB), `LSPServerManager` (extension→server routing, lazy startup, file tracking for didOpen). `passiveFeedback.ts` registers textDocument/publishDiagnostics handlers and feeds `LSPDiagnosticRegistry` (max 10 per file / 30 total, LRU dedup across turns). LSPTool exposes 9 operations (go-to-definition, find-references, hover, document/workspace symbols, call hierarchy).",rationale:"LSP is loaded lazily (vscode-jsonrpc only when actually used), crash recovery is per-server (one crash does not kill other language servers), and diagnostics are deduplicated across turns so the model does not see the same error twice.",insight:{label:"Source anchor",body:"`src/services/lsp/` + `src/tools/LSPTool/LSPTool.ts`. Plugin system (`src/services/lsp/config.ts`) loads server configs from plugins — so LSP servers can be distributed as plugins. `reinitializeLspServerManager()` re-inits after plugin refresh (issue #15521)."},tradeoffs:"Factory functions instead of classes make state encapsulation explicit but unusual in TypeScript. The passive diagnostic registry (push-based) means the model receives diagnostics as tool results, not as streaming noise during a turn.",alternatives:"Calling out to LSP ad-hoc per request is simpler but loses persistent server state, file tracking, and the passive diagnostic pipeline.",x:992,y:390,width:280,height:92},{id:"ccr-memory",title:"Memory System",tooltip:"memdir + RelevantMemories + SessionMemory + ExtractMemories + AutoDream — 5-layer",description:"Five-layer memory architecture: (1) `memdir` — project-scoped CLAUDE.md management with security validation (null bytes, URL-encoding, Unicode normalization, symlinks) and team memory support; (2) `RelevantMemories` — fires a lightweight Sonnet side-query before each turn to select at most 5 contextually appropriate memory files from memdir — this is how large memdirs scale without flooding context; (3) `SessionMemory` — auto-updating markdown via post-sampling hook (fires when ≥10k tokens + ≥3 tool calls), writes to `~/.claude/session-memory/<project>/memory/session-memory.md`; (4) `ExtractMemories` — turn-end background extraction with 4-type taxonomy (user/feedback/project/reference), stashing coalescer; (5) `AutoDream` — 5-gate background consolidation (enabled, 24h time, 10min throttle, 5 sessions, file-based lock) that fires `/dream` as a forked sub-agent.",rationale:"Each layer serves a different memory horizon: CLAUDE.md is manually curated permanent context, RelevantMemories is the per-turn selector that scales the static context, SessionMemory is short-term within-session notes, ExtractMemories is turn-level episodic capture, AutoDream is periodic long-term consolidation. The 4-type taxonomy (user/feedback/project/reference) explicitly excludes code patterns and git history — those are derivable.",insight:{label:"Source anchor",body:"`src/memdir/`, `src/services/relevantMemories/`, `src/services/SessionMemory/`, `src/services/extractMemories/`, `src/services/autoDream/`. Most descriptions stop at four layers — the fifth (RelevantMemories) is what makes large project memdirs practical: you pay only for what is contextually relevant to the current turn. AutoDream lock uses mtime-as-timestamp: PID body is for stale detection only."},tradeoffs:"Five overlapping layers add complexity but serve genuinely different durability and freshness needs. The memory staleness system (`memoryAgeDays`, `memoryFreshnessNote`) proactively warns the model before it acts on outdated information.",alternatives:"A single append-only file would be simpler but degrades on projects that span weeks: the model would receive an unmanageable amount of context or lose older information entirely.",x:44,y:570,width:280,height:92},{id:"ccr-exec",title:"Tool Execution",tooltip:"services/tools — batch scheduler, per-tool pipeline, streaming executor",description:"`toolOrchestration.ts` partitions batches into concurrent and serial groups via `partitionToolCalls()`, applying context modifiers in original block order (not completion order) for determinism. `toolExecution.ts` is the per-tool `runToolUse()` generator: resolve→abort-check→PreToolUse hooks→permission→execute with progress→serialize result. `StreamingToolExecutor.ts` starts tools speculatively while the model is still streaming; discard+tombstone pattern cleans up on fallback. `CLAUDE_CODE_MAX_TOOL_USE_CONCURRENCY` (default 10) caps parallelism. PreToolUse hooks returning `allow` cannot override deny rules or safety-check gates.",rationale:"Context modifier ordering (original block order not arrival order) prevents nondeterministic ToolUseContext state. The streaming executor overlaps model output latency with tool execution latency. Tombstone messages are cleanup signals, not error signals.",insight:{label:"Source anchor",body:"`src/services/tools/toolOrchestration.ts`, `toolExecution.ts`, `StreamingToolExecutor.ts`. Hook invariant: `resolveHookPermissionDecision()` ensures hooks cannot bypass policy. Alias fallback in `runToolUse()` handles renamed tools in old transcripts (e.g., `KillShell` → `TaskStop`)."},tradeoffs:"Speculative execution improves throughput but requires explicit discard-and-retry semantics on streaming fallback. The tombstone design treats fallback cleanup as a first-class event type.",alternatives:"Wait-for-full-response execution is simpler but wastes the latency overlap between model output and tool execution time.",x:360,y:570,width:280,height:92},{id:"ccr-tasks",title:"Task + Swarm + Coordinator",tooltip:"Task.ts / AgentTool / swarm — managed child runtimes",description:'Three-tier detached work system: (1) Task lifecycle — thin interface (name, type, kill()) with 5 types: shell, local_agent, remote_agent, local_main_session, dream. `LocalMainSessionTask` backgrounds the main query loop itself. (2) AgentTool routing — 6 launch paths (teammate, fork, sync, async, worktree, remote); fork mode preserves parent system prompt bytes + tool definitions for cache stability. (3) Swarm backends — `TmuxBackend` (binary tree pane layout, leader 30% / teammates 70%), `ITermBackend` (native panes), `InProcessBackend` (shared API client + MCP); `coordinatorMode.ts` adds orchestration system prompt guiding "synthesize first" delegation patterns. Team files persist on disk; permissionSync bridges cross-teammate permission prompts.',rationale:"The unified task surface makes all detached work (background shell, subagent, remote session, memory dream) observable and killable through one interface. Fork mode cache optimization shows the runtime thinks about delegation economics, not just correctness.",insight:{label:"Source anchor",body:"`src/Task.ts`, `src/tasks/`, `src/tools/AgentTool/`, `src/utils/swarm/`, `src/coordinator/`. `setAppState` is a no-op in async subagents; `setAppStateForTasks` always reaches the root store. InProcessTeammateTask caps messages at 50 to prevent memory leaks in long-running swarms."},tradeoffs:"Three execution backends (tmux, iTerm2, in-process) serve different environments. The pane creation lock prevents race conditions when spawning parallel teammates; shell init delay (200ms) accounts for slow shells (starship, oh-my-zsh).",alternatives:"Untracked background processes are simpler but make status, output, and cancellation impossible to surface without re-implementing the task infrastructure.",x:676,y:570,width:280,height:92},{id:"ccr-analytics",title:"Analytics + Observability",tooltip:"services/analytics + utils/telemetry — dual-sink, OTEL, Perfetto tracing",description:"Two-tier observability stack: (1) Analytics — `logEvent()` queues before sink attaches (no-dependency frontend), routes to dual sinks: Datadog (64-event whitelist, cardinality reduction, user bucket hashing sha256%30) and 1P first-party logger (`_PROTO_` fields for PII-tagged privileged BQ columns). Per-sink GrowthBook killswitches. Marker type `AnalyticsMetadata_I_VERIFIED_THIS_IS_NOT_CODE_OR_FILEPATHS = never` forces developer annotation. (2) Telemetry — OTEL spans for interactions/LLM requests/tools via AsyncLocalStorage, BigQuery metrics exporter, beta detailed tracing (60KB content limit), Perfetto Chrome Trace Event format (ant-only), plugin telemetry with hash-based privacy (sha256(name@marketplace+salt), truncated 16 chars).",rationale:"No-dependency analytics frontend prevents import cycles. Per-sink killswitches allow independent control of Datadog vs 1P during incidents. The `never` marker type catches accidental PII logging at compile time.",insight:{label:"Source anchor",body:"`src/services/analytics/` + `src/utils/telemetry/`. Beta tracing (`betaSessionTracing.ts`) deduplicates system prompts and tool schemas by hash within a session. `betaSessionTracing.ts` specifically extracts `<system-reminder>` tags and logs separately."},tradeoffs:"Queuing events before sink attachment adds memory overhead during early startup. The 64-event Datadog whitelist reduces costs and cardinality but requires explicitly registering every new event name.",alternatives:"A single logging library would be simpler but loses the per-sink kill-switch, the no-dependency guarantee, and the OTEL interoperability for distributed tracing.",x:992,y:570,width:280,height:92},{id:"ccr-ui",title:"UI Runtime + Prompt Suggestion",tooltip:"state/AppStateStore (75+ fields, 9 contexts) + ink.tsx + speculation",description:"Three-component UI layer: (1) State — `AppStateStore` with 75+ fields covering permissions, tasks, MCP state, plugins, bridge, sandbox, teams, ultraplan, voice, tmux/bagel/speculation, and more. External store exposed via `useSyncExternalStore` selectors. 9 React contexts (Voice, Stats, Notifications, FPS, Mailbox, Modal, Overlay, PromptOverlay, Queue). `onChangeAppState.ts` centralizes all state-change side effects. (2) Ink — custom terminal frame pipeline (React reconcile → Yoga layout → screen buffer → frame diff → patch write), raw mode, cursor parking, alt-screen, resize recovery. 3 screens: REPL.tsx (874KB), Doctor.tsx, ResumeConversation.tsx. (3) Prompt Suggestion — generates next-user-action suggestion via forked agent, 15+ quality filters; `speculation.ts` speculatively executes accepted suggestions in a forked agent with overlay directory, copying writes to main on acceptance.",rationale:"`getAppState()` is a function not a snapshot — permission checks re-read state after any `await`. `setAppStateForTasks` bypasses the no-op `setAppState` in async subagents so session-scoped infrastructure always reaches the root store. Speculation time savings metric (`speculationSessionTimeSavedMs`) tracks actual user value.",insight:{label:"Source anchor",body:"`src/state/AppStateStore.ts`, `src/ink/ink.tsx`, `src/services/PromptSuggestion/`, `src/screens/REPL.tsx`. QueryGuard (`idle → queuing → running → idle`) is embedded in REPL.tsx — it queues a second query submitted while one is running rather than dropping it, preventing interleaved turn state. REPL.tsx (5005 lines) is the composition root: 30+ hooks (usePermissions, useTask, useMcpState, usePlugin, useVoice, etc.) are mounted at startup, wiring state slices to UI behavior. Overlay priority stack governs z-ordering of modals, tool result overlays, and prompt overlays in the Ink frame pipeline. Prompt suggestion speculation uses a forked agent with a shadow overlay directory: accepted suggestions copy files to main, rejected suggestions are discarded."},tradeoffs:"A 75+ field state tree is hard to audit but reflects the reality that Claude Code is a session-scoped runtime, not a chat screen. Each field documents a real product concern.",alternatives:"React context with useState would couple mutation access to React tree membership, preventing non-React tool handlers from writing to state without callback bridges.",x:44,y:750,width:600,height:92},{id:"ccr-bridge",title:"Bridge + Remote Transport",tooltip:"bridge/remote/server — CCR WebSocket sessions, upstream proxy",description:"Full remote control stack: `bridge/` owns the CCR Environments API integration (V1: register → long-poll for work → spawn REPL child; V2 env-less: direct POST → worker JWT), OAuth-gated via `isBridgeEnabled()`, handles `control_request` (initialize, set_model, interrupt, set_permission_mode) with a ~10-14s response deadline. `remote/` is the client side: `SessionsWebSocket` (30s ping, 5 exponential-backoff reconnects), `RemoteSessionManager`, `sdkMessageAdapter` (SDK format → REPL message). `server/` is a direct session connector for headless/LSP/SDK integrations. `upstreamproxy/` runs a MITM relay in CCR containers (CONNECT→WebSocket via protobuf chunks, `prctl(PR_SET_DUMPABLE, 0)` to block heap dump, fail-open).",rationale:"The V1/V2 path split allows gradual migration away from the Environments API. BoundedUUIDSet prevents echo loops on reconnect. The upstream proxy injects credentials at the container boundary without exposing session tokens to container processes.",insight:{label:"Source anchor",body:'`src/bridge/`, `src/remote/`, `src/server/`, `src/upstreamproxy/`. Bridge requires Claude.ai OAuth (not API keys). `initReplBridge()` checks `isPolicyAllowed("allow_remote_control")` before proceeding. Session title is derived from Haiku (fast, fire-and-forget) then re-generated over full conversation context.'},tradeoffs:"The MITM proxy is complex but prevents container-level credential exposure. The fail-open design means a broken proxy does not block the session, just loses traffic routing.",alternatives:"A stateless webhook model is simpler but cannot support streaming, interruption, and permission flows that require persistent bidirectional connections.",x:680,y:750,width:652,height:92}],edges:[{id:"ccr-e1",from:"ccr-boot-bottom",to:"ccr-input-top",label:"init session → input loop"},{id:"ccr-e2",from:"ccr-boot-bottom",to:"ccr-cmd-top",label:"load commands"},{id:"ccr-e3",from:"ccr-boot-bottom",to:"ccr-auth-top",label:"auth / policy check"},{id:"ccr-e4",from:"ccr-boot-bottom",to:"ccr-mcp-top",label:"connect MCP servers"},{id:"ccr-e5",from:"ccr-boot-bottom",to:"ccr-memory-top",label:"inject memory context"},{id:"ccr-e6",from:"ccr-boot-bottom",to:"ccr-ui-top",label:"init app state"},{id:"ccr-e7",from:"ccr-input-right",to:"ccr-cmd-left",label:"/slash dispatch"},{id:"ccr-e8",from:"ccr-input-right",to:"ccr-query-left",label:"text prompt / speculative fork"},{id:"ccr-e9",from:"ccr-cmd-right",to:"ccr-query-left",label:"command result / prompt"},{id:"ccr-e10",from:"ccr-query-bottom",to:"ccr-exec-top",label:"tool_use batches"},{id:"ccr-e11",from:"ccr-query-bottom",to:"ccr-tasks-top",label:"spawn agent / background task"},{id:"ccr-e12",from:"ccr-exec-top",to:"ccr-query-bottom",label:"tool_result"},{id:"ccr-e13",from:"ccr-tasks-top",to:"ccr-query-bottom",label:"task output / agent result"},{id:"ccr-e14",from:"ccr-tool-proto-right",to:"ccr-perms-left",label:"permission hints"},{id:"ccr-e15",from:"ccr-exec-top",to:"ccr-perms-bottom",label:"checkPermissions()"},{id:"ccr-e16",from:"ccr-perms-bottom",to:"ccr-ui-top",label:"approval prompts"},{id:"ccr-e17",from:"ccr-mcp-left",to:"ccr-tool-proto-right",label:"wrap → Tool / Command / Resource"},{id:"ccr-e18",from:"ccr-lsp-left",to:"ccr-tool-proto-right",label:"code intelligence tools"},{id:"ccr-e19",from:"ccr-memory-right",to:"ccr-query-bottom",label:"memory context injection"},{id:"ccr-e20",from:"ccr-exec-bottom",to:"ccr-ui-top",label:"progress events"},{id:"ccr-e21",from:"ccr-tasks-bottom",to:"ccr-ui-top",label:"task status"},{id:"ccr-e22",from:"ccr-analytics-bottom",to:"ccr-ui-top",label:"observes all subsystems"},{id:"ccr-e23",from:"ccr-auth-bottom",to:"ccr-bridge-top",label:"OAuth token required"},{id:"ccr-e24",from:"ccr-bridge-top",to:"ccr-query-right",label:"remote prompt / control"},{id:"ccr-e25",from:"ccr-perms-bottom",to:"ccr-exec-top",label:"allow / deny → resume"},{id:"ccr-e26",from:"ccr-query-bottom",to:"ccr-memory-top",label:"post-turn extraction trigger"}]},{id:"agent-client-runtime",label:"Agent Client Runtime",emoji:"\uD83E\uDDED",tagline:"Sessions, permissions, plans, subagents, and remote transport",defaultSelectedId:"acr-executor",nodes:[{id:"acr-user",title:"User Surface",tooltip:"CLI or desktop UI where the session starts",description:"Terminal or desktop surface that owns the visible conversation and streams progress to the user.",rationale:"The client is not just a thin input box. It owns streaming, interruption, local context gathering, and the UX for approvals. In `learning-claude-code`, the client layer carries a real session model rather than delegating everything to a stateless backend.",insight:{label:"Terminology",body:'If this layer owns session state, tool approval UX, and transport, "agent client" is reasonable terminology. It is more than a chat frontend.'},tradeoffs:"A rich client improves responsiveness and can keep local affordances like file links or terminal state. The cost is complexity: state synchronization, resumability, and permission UX all move into the product surface.",alternatives:"A browser-only stateless chat UI is simpler, but it pushes hard problems like resumable sessions, local tool execution, and approval flows into a backend that now has to impersonate the user environment.",x:24,y:220,width:250,height:122},{id:"acr-session",title:"Session Manager",tooltip:"Stable session identity, resume and transcript state",description:"Persistent session identity, history, plan files, and resume/fork semantics across reconnects.",rationale:"The codebase treats sessions as first-class runtime entities. There are dedicated types for session IDs and stable session keys, plus plan and transcript persistence so a long-running task can survive client restarts or transport switches.",insight:{label:"State boundary",body:"Once a coding assistant can resume, fork, and background work, session management becomes infrastructure, not UI glue."},tradeoffs:"Strong session identity enables recovery and background execution. The cost is lifecycle management: cleanup, storage durability, and reconciling local state with remote state after reconnects.",alternatives:"Ephemeral request/response chats are easier to host but lose resumability. They also make multi-turn planning and background workers much harder to reason about.",x:330,y:220,width:250,height:122},{id:"acr-planner",title:"Planner / Coordinator",tooltip:"Creates plans and coordinates child agents",description:"Planning layer that decides when to explore, when to execute, and when to spin up helper agents.",rationale:"The repo has explicit plan mode controls, plan file persistence, and coordinator task UI. That points to a deliberate architecture: planning is treated as a separate mode with its own artifacts, not just prose emitted into chat history.",insight:{label:"Persistent plans",body:"A saved plan file gives the runtime a durable working memory that survives compaction better than raw transcript alone."},tradeoffs:"Explicit planning improves clarity on larger tasks and supports subagent work. The downside is latency and the risk of over-planning simple requests.",alternatives:"A purely reactive loop is faster for trivial edits but degrades on tasks that need decomposition, approval sequencing, or resumable progress tracking.",x:646,y:6,width:250,height:122},{id:"acr-tool-registry",title:"Tool Registry",tooltip:"Schemas, enablement, and runtime tool selection",description:"Central registry for built-in tools, feature-gated tools, and connected MCP capabilities.",rationale:"The runtime enumerates a large tool surface and conditionally enables pieces like web tools, REPL tools, worktree tools, and MCP-connected tools. That argues for a registry model rather than hard-coded prompt instructions.",tradeoffs:"A typed registry makes validation, discoverability, and analytics possible. The cost is maintenance pressure: tool definitions, flags, and permission policies must stay coherent as the surface grows.",alternatives:"Injecting ad hoc instructions into the prompt is faster to prototype, but it makes capability discovery, safety review, and UI integration much harder.",x:646,y:220,width:250,height:122},{id:"acr-permissions",title:"Permission Gate",tooltip:"Allow, deny, ask and approval transport",description:"Policy and approval layer that decides which tool calls are auto-allowed, auto-denied, or sent to the user for confirmation.",rationale:"In `learning-claude-code`, permission handling is its own subsystem with modes, rule sources, ask/deny/allow decisions, and bridge callbacks for `control_request` / `control_response`. That is the right mental model: safety is a runtime gate, not a prompt note.",insight:{label:"Critical edge",body:"Once the model can execute commands or file edits, the permission system is the real trust boundary."},tradeoffs:"Fine-grained rules reduce accidental damage and let safe work proceed automatically. The friction is extra UX and policy complexity, especially for background agents that cannot show prompts.",alternatives:"An all-or-nothing sandbox is simpler but either blocks too much useful work or grants too much power to the model.",x:646,y:444,width:250,height:122},{id:"acr-executor",title:"Execution Loop",tooltip:"Model loop that reasons, calls tools, and emits progress",description:"Main agent loop that assembles context, samples the model, executes tools, and feeds results back into the next step.",rationale:"This is the heart of the client. The surrounding files show a clear split between tool definitions, tool results, progress messages, and agent/task state. That is exactly what you need to turn a model into an operational runtime.",tradeoffs:"Centralizing the loop gives one place to implement retries, compaction, and usage tracking. The downside is that every concern eventually wants to hook into this loop, so boundaries need discipline.",alternatives:"Breaking execution across several loosely coordinated services can scale teams, but it usually makes debugging a single turn much harder.",x:962,y:220,width:250,height:122},{id:"acr-subagents",title:"Forked Agents",tooltip:"Parallel helper agents with isolated mutable state",description:"Subagents that share cache-safe prompt prefixes with the parent while isolating mutable state and tracking their own progress.",rationale:"The forked-agent utilities make the design explicit: child agents reuse cache-critical parameters, increment chain depth, and isolate UI callbacks unless explicitly shared. That is a strong pattern for parallel exploration without corrupting the main turn.",tradeoffs:"Subagents can accelerate bounded side work and improve responsiveness on broader tasks. They also introduce coordination overhead, extra usage cost, and more failure states around cancellation and merge-back.",alternatives:"Single-agent execution is simpler and often enough. Use subagents only when the tasks are bounded, parallelizable, and worth the extra runtime machinery.",x:962,y:6,width:250,height:122},{id:"acr-bridge",title:"Bridge / Remote Transport",tooltip:"Remote sessions, WebSocket streaming, and reconnect",description:"Transport layer for remote-control sessions, bridge-created sessions, and WebSocket subscription to remote output.",rationale:"The repo has dedicated bridge and remote session modules for creating sessions, subscribing over WebSockets, sending control responses, and handling reconnects. That means the client is designed to move beyond local-only execution.",insight:{label:"Transport matters",body:"If your client may hand work off to a remote runtime, transport design becomes part of the product architecture, not an implementation detail."},tradeoffs:"Remote transport enables handoff, detached execution, and richer device flows. It also creates new failure modes: token refresh, session-not-found races, and state drift between local and remote surfaces.",alternatives:"A local-only runtime is easier to trust and debug, but it cannot support cloud execution, cross-device continuation, or managed long-running sessions.",x:1278,y:220,width:250,height:122}],edges:[{id:"acr-e1",from:"acr-user-right",to:"acr-session-left",label:"start / resume"},{id:"acr-e2",from:"acr-session-right",to:"acr-tool-registry-left",label:"load context + tools"},{id:"acr-e3",from:"acr-tool-registry-right",to:"acr-executor-left",label:"available capabilities"},{id:"acr-e4",from:"acr-executor-left",to:"acr-permissions-right",label:"approval check"},{id:"acr-e5",from:"acr-permissions-top",to:"acr-user-bottom",label:"ask / approve"},{id:"acr-e6",from:"acr-executor-top",to:"acr-subagents-bottom",label:"delegate bounded work"},{id:"acr-e7",from:"acr-subagents-left",to:"acr-planner-right",label:"results"},{id:"acr-e8",from:"acr-planner-bottom",to:"acr-tool-registry-top",label:"plan-aware tool choice"},{id:"acr-e9",from:"acr-session-top",to:"acr-planner-left",label:"plan / transcript state"},{id:"acr-e10",from:"acr-executor-right",to:"acr-bridge-left",label:"remote session stream"},{id:"acr-e11",from:"acr-bridge-left",to:"acr-session-right",label:"reconnect / resume"}]},{id:"ai-agent",label:"AI Agent Stack",emoji:"\uD83E\uDD16",tagline:"LLM orchestration with RAG and MCP tools",defaultSelectedId:"orchestrator",nodes:[{id:"web-ui",title:"Web UI",tooltip:"User-facing interface for agent sessions",description:"User-facing web surface for workflows, monitoring, and interactive agent sessions.",rationale:"A browser-based surface is the right default entry point for most users. It enables rich interaction patterns — session history, streaming output, real-time status — that a terminal interface cannot match without significant investment. For teams onboarding non-technical users, discoverability is a first-class requirement.",tradeoffs:"The upside is immediate: polished, accessible experience with zero installation friction. The downside is complexity — a reactive front-end adds a JavaScript build pipeline, client-side state management, and browser compatibility concerns to the operational surface. For internal tools used by a technical team, this cost often exceeds the value.",alternatives:"A CLI is a serious alternative and may be the better default if your primary users are engineers. A desktop app (Electron or Tauri) closes some of the gap — offline capability, filesystem access — but ships significantly more complexity than a web build.",x:-6,y:100,width:250,height:120},{id:"cli",title:"CLI",tooltip:"Scriptable automation for CI pipelines",description:"Scriptable automation interface for power users and CI pipelines.",rationale:"Batch execution and scriptability are properties you cannot retrofit onto a GUI. The CLI is the right interface for CI pipelines, scheduled jobs, and power users who need to compose the agent with other tools. It also doubles as the fastest iteration surface during development.",insight:{label:"Design sequence",body:"Build the CLI first. If the core API is well-designed, the web UI is a thin rendering layer on top of it. If you build the GUI first, you bake assumptions into the backend that make CLI ergonomics awkward later."},tradeoffs:"Low overhead, trivially automatable, and integrates naturally into any shell script or CI step. The tradeoff is discoverability: new users have no visual affordances, so every non-obvious flag must be documented and error messages must guide recovery without a UI to help.",alternatives:"A web-only approach works when the user base is non-technical, but sacrifices automation. A task runner UI (Temporal, Prefect) gives scheduling and visibility but introduces another system to operate.",x:104,y:100,width:250,height:120},{id:"api-gateway",title:"API Gateway",tooltip:"Unified auth, routing and traffic control",description:"Unified ingress handling auth, routing, policies, and traffic management.",rationale:"All clients — web, CLI, external integrations — funnel through a single ingress point. This is where cross-cutting concerns belong: authentication verification, rate limiting, request logging, circuit breaking. Handling these per-service instead creates inconsistent security posture and duplicated logic.",insight:{label:"The enforcement boundary",body:"The gateway is not just a router. If auth or rate limiting lives anywhere else, you will eventually have a service that skips it."},tradeoffs:"One place to audit, one place to add a policy, one place to observe traffic. The risk is that the gateway becomes a bottleneck or a single point of failure — a deployment concern, not a design flaw, provided you scale and replicate it properly.",alternatives:"A service mesh (Istio, Linkerd) handles similar concerns at the network layer via sidecar proxies, removing the gateway as a choke point but adding significant operational overhead. Direct service exposure works at small scale but breaks down as soon as you need consistent auth or per-client rate limiting.",x:-6,y:590,width:250,height:120},{id:"orchestrator",title:"Orchestrator",tooltip:"Coordinates multi-step execution plans",description:"Coordinates tool calls, retries, and multi-step execution plans across the agent.",rationale:"Multi-step agent tasks are inherently stateful: they involve sequences of tool calls, conditional branches, retries on failure, and compensation logic when partial steps succeed. Encoding this in a stateless function chain produces fragile, hard-to-debug flows. The orchestrator is where execution state is made explicit.",insight:{label:"Why complexity concentrates here",body:"The orchestrator is the only component that knows about time — what has happened, what is pending, and what to do if something fails. That is why it is the hardest to design."},tradeoffs:"The gain is resilience and observability: you can inspect the execution graph, replay from a checkpoint, and add timeouts or retries in one place. The cost is stateful infrastructure to operate — every workflow change is a migration concern if running instances are mid-execution on deploy.",alternatives:"Pure event choreography scales well for simple flows but becomes very hard to reason about when errors occur across multiple steps. Serverless chained functions (Step Functions, Durable Functions) are a managed middle ground — orchestration without the operational burden, but with execution cost and vendor lock-in.",x:-6,y:230,width:250,height:120},{id:"rag-service",title:"RAG Service",tooltip:"Retrieves and ranks context before generation",description:"Retrieval layer that fetches and ranks relevant context before generation.",rationale:"An LLM without retrieval has a knowledge cutoff and no awareness of your private data. RAG closes both gaps at inference time by fetching relevant context just before the prompt is assembled — enabling a model to reason over your documents and live systems without fine-tuning.",insight:{label:"Scope, not accuracy",body:"RAG is not primarily about accuracy — it is about scope. A well-tuned retrieval step defines what the model is allowed to know for this query. That boundary is what makes outputs auditable and controllable."},tradeoffs:"When retrieval is good, the model is grounded and precise. When retrieval fails — returning irrelevant chunks or missing the right document — the model often hallucinates with high confidence. There is also a latency cost: every request includes a vector search round-trip before the LLM call.",alternatives:"A prompt-only approach (static context in the system prompt) eliminates retrieval latency but is limited by context window size and cannot handle dynamic data. A fine-tuned domain model embeds knowledge into weights rather than retrieving it at runtime — better for stable, well-structured knowledge but expensive to retrain and inflexible to updates.",x:-6,y:400,width:250,height:120},{id:"mcp-server",title:"MCP Server",tooltip:"Schema-driven tool protocol for model integrations",description:"Standardized tool protocol layer for model-integrated capabilities and extensions.",rationale:"Tool integration without a standard contract means every provider, every model version, and every new capability requires custom adapter code. MCP defines a schema-driven protocol so tools declare their interface once and any compatible client can invoke them.",insight:{label:"Where the value lies",body:"The value of MCP is not the protocol itself — it is the boundary it draws. By making tools responsible for their own schema and validation, you keep the orchestrator generic and the tools independently deployable."},tradeoffs:"Unified contracts and reusable adapters across providers are the core payoff. The tradeoff is versioning complexity: a schema change in a tool must be coordinated with any client that depends on it, and debugging an MCP failure requires understanding both the protocol layer and the underlying tool.",alternatives:"Ad-hoc tool APIs (plain REST or function calls) are simpler to start with but do not compose well across providers. Direct SDK integration per provider gives maximum control at the cost of binding your orchestrator to specific vendor interfaces — switching providers requires rewriting tool call logic.",x:384,y:100,width:250,height:120},{id:"llm",title:"LLM",tooltip:"Core reasoning and language generation engine",description:"Reasoning and generation engine responsible for synthesis and response quality.",rationale:"The LLM is the reasoning core of the agent. Its job is not to execute actions — the orchestrator and tools handle that — but to decompose intent into steps, select the right tool for each step, and synthesise coherent responses from retrieved context and tool results.",insight:{label:"Planner, not database",body:"Treat the LLM as a planner, not a source of facts — that is what RAG and tool calls are for. Its strength is synthesising information it has been given into structured, actionable output."},tradeoffs:"Strong reasoning, natural language fluency, and generalisation are the obvious benefits. The costs are token price and latency variability. At high request volume, LLM calls are the largest cost driver in the stack, and response latency scales with output length.",alternatives:"Smaller, locally-hosted models (Llama, Mistral) reduce cost and data-residency concerns but require infrastructure for serving and typically produce lower-quality outputs on complex reasoning tasks. Rule-based orchestration eliminates the LLM entirely — appropriate for narrow, well-specified workflows but not for general-purpose agents.",x:-6,y:750,width:250,height:120},{id:"vector-db",title:"Vector DB",tooltip:"Fast semantic search over embedded documents",description:"Semantic index for embedding-based search and low-latency context retrieval.",rationale:"Semantic retrieval over large document corpora requires Approximate Nearest Neighbour search over high-dimensional embedding vectors — a workload general-purpose databases cannot serve efficiently. A vector database is purpose-built: it indexes embeddings at ingest and executes similarity queries in milliseconds against millions of vectors.",insight:{label:"What to measure",body:'The vector DB is not the intelligence of the RAG system — the LLM is. Its only job is to answer: "which chunks are most relevant to this query vector?" Evaluate it on search latency and recall, not semantic properties.'},tradeoffs:"Purpose-built stores (Pinecone, Qdrant, Weaviate) give the best ANN performance and support hybrid search. The main cost is index lifecycle management: embeddings must be regenerated when the underlying model changes, and the index must stay fresh as source documents are updated.",alternatives:"Postgres with pgvector is a strong alternative for smaller corpora — it collapses infrastructure to a single database and is sufficient up to a few million vectors with modest latency requirements. OpenSearch kNN is appropriate if you are already running OpenSearch for full-text search and want to add vector capability without a new system.",x:394,y:240,width:250,height:120},{id:"tools",title:"Tools",tooltip:"External integrations for real-world actions",description:"External integrations for actions, side effects, and business operations.",rationale:"An agent that can only generate text cannot complete real work. Tools are the bridge to the world: they allow the agent to query APIs, read files, execute code, update databases, and trigger workflows. Without tools, every agent session terminates at the output buffer.",insight:{label:"Tool design is security design",body:"Every tool is a potential code execution path. Define tools with the minimum capability they need, validate inputs before execution, and treat every tool call as untrusted input from the model."},tradeoffs:"The power of tools is proportional to their scope — broader tools enable more capable agents, and the risk scales the same way. Read-only tools are almost always safe; write tools require explicit user confirmation or strict scope boundaries to prevent unintended side effects.",alternatives:"A read-only mode — where the agent retrieves information but does not execute actions — is the right starting point for most deployments. It limits capability but eliminates the entire class of unintended write-side effects. Manual human-in-the-loop workflows preserve this safety property while allowing humans to approve actions before execution.",x:404,y:430,width:250,height:120}],edges:[{id:"a-e1",from:"web-ui-right",to:"api-gateway-left",label:"requests"},{id:"a-e2",from:"cli-top",to:"api-gateway-bottom",label:"ops commands"},{id:"a-e3",from:"api-gateway-right",to:"orchestrator-left",label:"dispatch"},{id:"a-e4",from:"orchestrator-right",to:"rag-service-left",label:"context fetch"},{id:"a-e5",from:"orchestrator-right",to:"mcp-server-top",label:"tool calls"},{id:"a-e6",from:"rag-service-right",to:"vector-db-left",label:"semantic retrieve"},{id:"a-e7",from:"rag-service-bottom",to:"llm-left",label:"grounded prompt"},{id:"a-e8",from:"mcp-server-bottom",to:"tools-right",label:"invoke"},{id:"a-e9",from:"tools-top",to:"orchestrator-bottom",label:"result stream"},{id:"a-e10",from:"llm-left",to:"orchestrator-right",label:"reasoning output"}]},{id:"microservices",label:"Microservices",emoji:"⚙️",tagline:"Event-driven service mesh with async bus",defaultSelectedId:"ms-api-gw",nodes:[{id:"ms-client",title:"Client",tooltip:"Web or mobile front-end application",description:"Web or mobile client that initiates requests to the service mesh.",rationale:"The client is where user intent enters the system. Every latency, reliability, and security decision in the stack ultimately traces back to what the client requested and when. Decoupling the client from backend services allows both to evolve independently — a new API version does not require a simultaneous client release.",tradeoffs:"Deployment independence and multi-platform reach are the main advantages. The cost is the API surface: anything the client needs must be versioned and maintained as a public contract. Client-side caching, optimistic updates, and network failure handling add non-trivial complexity for a polished user experience.",alternatives:"Server-rendered pages (Next.js, Rails) collapse the client-server boundary and simplify state management at the cost of flexibility. A native desktop app gives better system integration and offline capability but multiplies the deployment surface.",x:474,y:270,width:250,height:120},{id:"ms-api-gw",title:"API Gateway",tooltip:"Single entry point for all service calls",description:"Central entry point routing requests to downstream services with auth and rate-limiting.",rationale:"In a microservices architecture, the API gateway is the only layer that sees all traffic. It is the right place to enforce authentication, validate tokens before any service processes a request, and apply rate limits uniformly. Without it, each service must implement these independently — and they will do so inconsistently.",insight:{label:"What routing hides",body:"The gateway's value is not routing — that is trivial. Its value is enforcement. Move auth, rate limiting, and request validation here, and every downstream service can assume the request is legitimate."},tradeoffs:"A centralized gateway simplifies cross-cutting concerns and gives a single place to audit access patterns. The risk is becoming a bottleneck — both operationally (every service change may require a gateway update) and at runtime (every request is in the critical path). Horizontal scaling and careful capacity planning are required.",alternatives:"Direct service calls from the client work at small scale but become unmanageable as the number of services grows. A service mesh (Istio, Linkerd) handles similar concerns at the network layer via sidecars, avoiding the bottleneck at the cost of much higher operational complexity.",x:-6,y:100,width:250,height:120},{id:"ms-auth",title:"Auth Service",tooltip:"JWT/OAuth token validation and issuance",description:"Handles identity verification, JWT issuance, and OAuth 2.0 flows.",rationale:"Authentication is one of the few concerns in a distributed system where inconsistency is catastrophic. Centralizing JWT issuance and validation ensures all downstream services share the same security model, the same token lifetime policies, and the same revocation mechanism.",insight:{label:"Hot path vs cold path",body:"The auth service must not be a synchronous dependency on the hot path. Token validation should be local — verify the JWT signature against a shared public key — not a remote call on every request. The auth service handles issuance and revocation, not validation."},tradeoffs:"Consistent security policy and centralized token revocation are the primary gains. The risk is that the auth service becomes a critical dependency: if it is unavailable, no new sessions can be established. The latency concern is largely mitigated if validation is done locally via shared signing keys.",alternatives:"Per-service auth is a common early-stage pattern but creates security fragmentation — one service's looser validation can become an attack vector for all others. External identity providers (Auth0, Cognito) offload the entire burden but introduce vendor dependency and may not support all token lifecycle requirements.",x:-6,y:100,width:250,height:120},{id:"ms-user",title:"User Service",tooltip:"Manages user profiles and preferences",description:"Owns user profile data, preferences, and account lifecycle operations.",rationale:"User profile data is a distinct bounded context from authentication, ordering, and analytics. Owning it in a dedicated service makes PII handling auditable, simplifies compliance (GDPR deletion requests touch one service, not ten), and lets the responsible team evolve the schema independently.",tradeoffs:"Clear data ownership and isolated compliance scope are the primary advantages. The tradeoffs are distributed data consistency — a user deletion must propagate to every service that cached user data — and the network overhead of a service call for every user lookup. Aggressive caching at the caller mitigates latency but adds cache invalidation complexity.",alternatives:"A shared user table in a monolith is the right choice before you have a reason to split — premature extraction adds operational complexity without benefit. Auth service + profile extension is a reasonable middle ground, but risks conflating authentication identity with application profile data.",x:-6,y:610,width:250,height:120},{id:"ms-order",title:"Order Service",tooltip:"Order lifecycle and fulfilment processing",description:"Processes order placement, status tracking, and fulfilment coordination.",rationale:"Order processing is stateful, complex, and high-stakes: it involves a state machine (placed → confirmed → fulfilled → shipped), coordination with inventory and payment systems, and failure handling that requires compensating transactions. This complexity justifies a dedicated service with a clear owner.",insight:{label:"Audit trail by default",body:"Order state transitions are the system's most sensitive writes. Every state change should be an event, not an in-place update — this makes the audit trail free and enables replaying the order history from events."},tradeoffs:"An encapsulated order state machine with its own deployment pipeline means order logic can be changed, tested, and scaled independently. The cost is distributed transactions: a failed payment after an inventory reservation requires compensating logic (the saga pattern), which is the hardest part of order service design.",alternatives:"A combined user+order service is common in early-stage systems and reduces network overhead. CQRS with separate read/write services is appropriate when order query volume is very high and read models need to be optimized independently of writes.",x:-6,y:330,width:250,height:120},{id:"ms-eventbus",title:"Event Bus",tooltip:"Async message broker for domain events",description:"Durable async message broker (Kafka / RabbitMQ) that decouples producers from consumers.",rationale:"Synchronous service-to-service calls create temporal coupling: if the notification service is slow, the order service becomes slow. An async event bus decouples producers from consumers — the order service emits an event and moves on, regardless of how many consumers process it or how quickly.",insight:{label:"How failures change character",body:"With synchronous calls, a consumer failure propagates upstream. With async events, the bus absorbs the failure — the consumer catches up when it recovers, without any change to the producer."},tradeoffs:"Temporal decoupling, at-least-once delivery guarantees, and easy fan-out to new consumers are the core benefits. The costs are message ordering (per-partition ordering only in Kafka, not global) and consumer lag monitoring — a slow consumer accumulates lag invisibly until it causes problems.",alternatives:"Synchronous REST calls are simpler to understand and debug but create tight coupling that causes cascading failures. gRPC streaming is appropriate for high-throughput, low-latency scenarios but is harder to operate and does not naturally support fan-out to multiple consumers.",x:-6,y:100,width:250,height:120},{id:"ms-notification",title:"Notification",tooltip:"Sends email, SMS and push notifications",description:"Dispatches email, SMS, and push notifications triggered by domain events.",rationale:"Notification delivery is a distinct operational concern with requirements that do not belong in any business service: retry with exponential backoff, provider failover (SendGrid down → Mailgun), per-user preference management, and delivery status tracking. Pulling this out keeps the order and user services focused on their core domain.",tradeoffs:"Multi-channel delivery and retry logic in one place with clear ownership is the primary gain. The cost is provider dependency — if your email provider has an outage, notifications queue up and you need to handle the burst on recovery. Delivery status tracking also adds complexity if required downstream.",alternatives:"Inline notification in the User Service is tempting (fewer moving parts) but conflates two concerns: managing users and reaching them. Third-party CDPs (Braze, Iterable) handle the entire notification surface including templates, scheduling, and analytics — appropriate if notification sophistication is a product requirement, not just a technical one.",x:-6,y:610,width:250,height:120},{id:"ms-report",title:"Report Service",tooltip:"Analytical reporting from event streams",description:"Consumes domain events to build analytical reports and operational dashboards.",rationale:"Read-heavy analytical queries running against the same database as transactional writes create noisy-neighbour contention. A reporting service consumes events from the bus and builds read models optimised for analytical access patterns, isolating the write path from expensive aggregation queries.",tradeoffs:"No write-path contention and independently scalable read models are the gains. The cost is eventual consistency — reports reflect the event stream up to the point it has been processed, not the absolute latest transactional state. For most reporting use cases this is acceptable; for compliance or billing, it may not be.",alternatives:"Direct DB queries on the OLTP store work at low traffic volumes and eliminate the event processing layer. A dedicated data warehouse (Redshift, BigQuery) is the right choice when reporting requirements are complex, historical, or require joins across multiple services.",x:364,y:330,width:250,height:120},{id:"ms-postgres",title:"PostgreSQL",tooltip:"Relational persistence for service data",description:"Shared relational database with per-service schemas for durable persistence.",rationale:"PostgreSQL is the correct default for service persistence in a microservices system. It provides ACID guarantees, a rich query language with JSON support, full-text search, and a mature ecosystem of tools. Most importantly, it has a 30-year track record of correctness under load.",insight:{label:"The actual anti-pattern",body:"The shared database anti-pattern — multiple services coupling to the same schema — is what you should avoid, not PostgreSQL itself. Per-service schemas, or separate databases per service, preserves the benefits while maintaining service isolation."},tradeoffs:"ACID guarantees and rich querying capability are the core benefits. Vertical scaling limits are real — a single Postgres instance tops out at some write throughput ceiling, and horizontal write scaling requires sharding or a different database. Schema migrations also require coordination when multiple services share an instance.",alternatives:"Per-service databases on different engines (polyglot persistence) allow each service to choose the right storage model but significantly increase operational surface. CockroachDB is the right choice when you need distributed ACID guarantees across regions — it is wire-compatible with Postgres but adds significant operational complexity.",x:454,y:100,width:250,height:120}],edges:[{id:"m-e1",from:"ms-client-right",to:"ms-api-gw-left",label:"HTTPS"},{id:"m-e2",from:"ms-api-gw-right",to:"ms-auth-left",label:"validate"},{id:"m-e3",from:"ms-api-gw-right",to:"ms-user-left",label:"user ops"},{id:"m-e4",from:"ms-api-gw-right",to:"ms-order-left",label:"order ops"},{id:"m-e5",from:"ms-user-right",to:"ms-eventbus-left",label:"user events"},{id:"m-e6",from:"ms-order-right",to:"ms-eventbus-left",label:"order events"},{id:"m-e7",from:"ms-eventbus-right",to:"ms-notification-left",label:"notify"},{id:"m-e8",from:"ms-eventbus-right",to:"ms-report-left",label:"stream"},{id:"m-e9",from:"ms-user-right",to:"ms-postgres-left",label:"query"},{id:"m-e10",from:"ms-order-right",to:"ms-postgres-left",label:"persist"}]},{id:"data-pipeline",label:"Data Pipeline",emoji:"\uD83D\uDD04",tagline:"Stream ingestion to ML feature serving",defaultSelectedId:"dp-transform",nodes:[{id:"dp-sources",title:"Data Sources",tooltip:"Databases, APIs and event streams",description:"Origin systems: transactional databases, third-party APIs, clickstream events, and IoT sensors.",rationale:"The value of a data pipeline is proportional to the diversity and quality of its inputs. Ingesting broadly — transactional databases, third-party APIs, clickstream events — gives analytical models the cross-domain signal needed for accurate features. A pipeline reading from a single system cannot answer cross-cutting business questions.",tradeoffs:"Rich signal diversity and comprehensive data lineage are the core benefits. The primary risk is schema drift: when a source system changes its output format without notice, downstream jobs break silently or produce incorrect results. Strict schema contracts at ingest time (Avro, Protobuf) surface these breakages early.",alternatives:"Single-source pipelines are simpler to operate and debug but constrain analytical scope to one system's data. Direct BI tool connections (Tableau → Postgres) eliminate the pipeline entirely for simple cases but do not scale to complex transformations or large data volumes.",x:-6,y:610,width:250,height:120},{id:"dp-ingest",title:"Ingest Layer",tooltip:"Kafka / Kinesis event ingestion connectors",description:"Durable event ingestion layer (Kafka / Kinesis) that buffers and distributes raw data.",rationale:"A durable ingest layer decouples source systems from downstream processing speed. Without it, a slow processing step applies backpressure directly to the source — a production database that cannot write fast enough because an analytics job is struggling is a serious availability risk.",insight:{label:"What Kafka actually gives you",body:"Kafka's core feature is not messaging — it is log retention. Consumers can replay from any offset, so you can add a new downstream consumer without any change to the producer, and recover from a processing failure without re-querying the source."},tradeoffs:"Backpressure handling, replay capability, and multiple consumer support are the primary gains. Kafka in particular requires careful operational management: topic partitioning strategy, retention policies, consumer group lag monitoring, and schema registry maintenance are all non-trivial. The complexity is justified at scale; at small data volumes, often not.",alternatives:"Direct DB extraction (polling or CDC via Debezium) works well for single-source pipelines and is simpler to operate. Webhook push to S3 is appropriate for third-party APIs that already support event delivery, eliminating the need for a polling connector.",x:-6,y:330,width:250,height:120},{id:"dp-stream",title:"Stream Processor",tooltip:"Real-time enrichment and aggregation",description:"Real-time processing engine (Apache Flink / Spark Streaming) for enrichment and windowed aggregations.",rationale:"Batch processing cannot produce sub-second features or detect anomalies in real time. A stream processing engine runs continuously, consuming events as they arrive, maintaining stateful aggregations across time windows, and emitting enriched records downstream. This is the only way to power live dashboards or real-time fraud signals.",tradeoffs:"Sub-second latency and stateful windowing are the distinctive capabilities of stream processing. The operational cost is high: tuning parallelism, managing state backends (RocksDB in Flink), handling late-arriving events, and recovering stateful jobs after failure all require deep expertise. For workloads where 5-minute batch latency is acceptable, Spark batch is far simpler.",alternatives:"Micro-batch Spark (Structured Streaming) is a reasonable middle ground — it processes small batches continuously and is simpler to operate than true streaming. KSQL on Kafka Streams is appropriate when processing stays simple (filters, projections, simple joins) and the team is already deep in the Kafka ecosystem.",x:-6,y:100,width:250,height:120},{id:"dp-lake",title:"Data Lake",tooltip:"Raw storage in object store (S3/GCS)",description:"Immutable raw storage layer in object store (S3 / GCS) for batch reprocessing and audit.",rationale:"Raw data retention is the foundation of a reprocessable pipeline. When a transformation bug is discovered months after the fact, the ability to replay from raw events is what separates a recoverable incident from a data loss event. The lake stores data exactly as received, before any transformation opinion is applied.",insight:{label:"The insurance policy",body:"The data lake's primary value is often realized in scenarios you hope never happen: audit requests, compliance investigations, model retraining from historical data, and pipeline backfills after bugs are fixed."},tradeoffs:"Unlimited retention and cheap storage at scale are the benefits — object storage costs a fraction of a data warehouse. The cost is no query performance guarantees: querying raw Parquet files directly is slow without a compute layer. Data quality is also deferred — the lake stores whatever arrives, good or bad.",alternatives:"A data warehouse-only approach (Snowflake, Redshift) skips raw retention in favor of transformed, queryable data. This is simpler but means you cannot backfill if transformation logic turns out to be wrong. A Lakehouse (Delta Lake, Apache Iceberg) adds ACID transactions and time-travel to object storage, giving most of the warehouse benefits without leaving the lake.",x:-6,y:580,width:250,height:120},{id:"dp-transform",title:"Transform Engine",tooltip:"dbt / Spark batch data modelling layer",description:"Batch transformation layer (dbt / Spark) that models raw data into clean analytical tables.",rationale:"Raw ingested data is rarely in a form that analysts or ML models can use directly. The transform engine models raw events into clean, tested, documented tables with business semantics applied. dbt in particular makes transformations version-controlled, testable, and documented alongside the code.",insight:{label:"When data becomes a product",body:"Everything downstream — analytics, features, reports — should be reading from tested, versioned models, not from raw tables. If a team is writing queries directly against raw data, the transform layer is not doing its job."},tradeoffs:"Version-controlled models, data quality tests, and a lineage graph are the primary benefits. dbt requires SQL expertise and produces only SQL transformations — complex Python logic still needs Spark or a separate job. Batch latency is also inherent: dbt models run on a schedule, not continuously.",alternatives:"ELT with warehouse compute only (Snowflake Tasks, BigQuery Scheduled Queries) eliminates dbt but loses version control and the testing framework. Custom PySpark jobs give maximum flexibility for complex transformations but require a Python and Spark skillset and produce harder-to-maintain code at scale.",x:-6,y:340,width:250,height:120},{id:"dp-features",title:"Feature Store",tooltip:"Shared online and offline ML features",description:"Centralised store for online (low-latency) and offline (batch training) ML features.",rationale:"Without a feature store, every ML team recomputes the same features independently and subtly differently. A feature store enforces a single definition for each feature and makes it available for both offline training and online serving — eliminating the training-serving skew that is the most common cause of production model degradation.",insight:{label:"Training-serving skew",body:"Skew is not a model problem — it is a data problem. The feature store eliminates it by ensuring the feature computation used during training is identical to the computation used at serving time."},tradeoffs:"Feature reuse, training-serving parity, and point-in-time correctness (preventing label leakage) are the core benefits. The infrastructure overhead is real: a feature store requires both an offline store (for training) and an online store (for serving), with a pipeline keeping them in sync. For small teams with one or two models, the coordination overhead may exceed the benefit.",alternatives:"Ad-hoc feature scripts per model work at small scale and require no shared infrastructure, but diverge quickly across teams. Warehouse-only features (compute everything in the data warehouse) is simpler and sufficient for batch prediction use cases, but cannot serve features at online inference latency.",x:324,y:100,width:250,height:120},{id:"dp-training",title:"ML Training",tooltip:"Scheduled model training and evaluation",description:"Scheduled training jobs that consume features and produce versioned model artifacts.",rationale:"Models that are not retrained eventually drift — the data distribution shifts, the world changes, and predictions become less accurate. Automated retraining with versioned artifacts, tracked experiments, and evaluation gates before promotion is what separates a production ML system from a research prototype.",tradeoffs:"Reproducible experiments, automated retraining triggered by data drift or schedule, and model versioning are the core benefits. The costs are compute (GPU training jobs are expensive) and long iteration cycles — a training run that takes hours to validate a hypothesis slows the experimentation loop significantly.",alternatives:"Manual training runs are appropriate during initial development and for infrequently changing models. AutoML platforms (Vertex AI, SageMaker Autopilot) automate hyperparameter search and model selection at the cost of reduced control over model architecture.",x:1280,y:313,width:250,height:120},{id:"dp-serving",title:"Serving API",tooltip:"Low-latency prediction endpoint",description:"Low-latency prediction service that loads model artifacts and serves inference requests.",rationale:"Inference has different performance requirements from training: sub-100ms latency, high throughput, graceful degradation under load, and A/B testing without redeployment. A dedicated serving layer decouples these requirements from training infrastructure and lets each scale independently.",tradeoffs:"Predictable latency SLOs, A/B testing support, and independent horizontal scaling are the primary benefits. Cold-start on model load (large models take seconds to load into GPU memory) is a real limitation that requires pre-warming. Model staleness between deploy cycles is also a concern if models need to be updated continuously.",alternatives:"Embedding the model in the application server eliminates a network hop and simplifies the stack — the right choice for small models at low traffic. Batch prediction only — scoring offline and writing results to a database — eliminates serving latency entirely but cannot support interactive use cases.",x:1580,y:203,width:250,height:120}],edges:[{id:"d-e1",from:"dp-sources-right",to:"dp-ingest-left",label:"CDC / events"},{id:"d-e2",from:"dp-ingest-right",to:"dp-stream-left",label:"real-time"},{id:"d-e3",from:"dp-ingest-right",to:"dp-lake-left",label:"raw store"},{id:"d-e4",from:"dp-stream-right",to:"dp-transform-left",label:"enriched"},{id:"d-e5",from:"dp-lake-right",to:"dp-transform-left",label:"batch read"},{id:"d-e6",from:"dp-transform-right",to:"dp-features-left",label:"features"},{id:"d-e7",from:"dp-transform-right",to:"dp-training-left",label:"training data"},{id:"d-e8",from:"dp-features-right",to:"dp-serving-left",label:"lookup"},{id:"d-e9",from:"dp-training-right",to:"dp-serving-left",label:"model weights"}]},{id:"edge-cdn",label:"Edge / CDN",emoji:"\uD83C\uDF10",tagline:"Global delivery with edge compute layer",defaultSelectedId:"ec-shield",nodes:[{id:"ec-browser",title:"Browser",tooltip:"End-user client initiating HTTP requests",description:"End-user client (browser or mobile) making HTTP requests to the CDN edge layer.",rationale:"The browser is the universal client runtime. It requires no installation, runs on every platform, and supports progressive enhancement — slow connections still get a functional experience. For any user-facing web property, the browser is the default deployment target.",tradeoffs:"Zero-install reach and progressive enhancement are the primary advantages. The constraints are real: browser APIs are sandboxed, JavaScript performance is bounded, and client-side caching behaviour varies across vendors. Heavy computation must stay on the server or be offloaded to WebAssembly.",alternatives:"Native app clients (iOS, Android) give better system integration, offline capability, and performance for compute-intensive workloads. Server-side rendering only simplifies the architecture and is the right choice when client-side interactivity is limited.",x:0,y:83,width:250,height:120},{id:"ec-waf",title:"WAF",tooltip:"DDoS and bot traffic filtering layer",description:"Web Application Firewall filtering DDoS attacks, SQL injection, and malicious bot traffic.",rationale:"Malicious traffic blocked at the edge never reaches your origin. A WAF absorbs DDoS, filters SQL injection and XSS attempts, and fingerprints known bot patterns before any packet touches your application infrastructure. At high traffic volumes, origin-level filtering is too expensive — the WAF is where you shed load.",insight:{label:"Not a substitute",body:"A WAF is not a substitute for application-level input validation — it is a first line of defence that reduces noise. Every input that reaches the application must still be validated by the application, regardless of what the WAF filtered."},tradeoffs:"Origin protection and managed rule sets that respond to new CVEs without application changes are the primary benefits. The risk is false positives: overly aggressive rules block legitimate traffic, causing customer-visible errors. Rule tuning is an ongoing operational responsibility, not a one-time setup.",alternatives:"Origin-level firewall rules (security groups, iptables) are simpler to manage but cannot inspect HTTP payloads or block application-layer attacks. Cloudflare Turnstile and similar bot detection tools address the bot traffic use case specifically, with lower false positive risk than a full WAF rule set.",x:310,y:83,width:250,height:120},{id:"ec-cdn",title:"CDN PoP",tooltip:"Globally distributed cache at the edge",description:"Globally distributed cache nodes (Points of Presence) serving assets from the nearest location.",rationale:"Latency is determined by the speed of light — a user in Tokyo requesting an origin server in Virginia will wait for the full round-trip propagation delay regardless of server speed. A CDN cache collapses this to a request to the nearest PoP, often milliseconds away. For cacheable content, this is a 10–50\xd7 latency improvement.",insight:{label:"The real performance lever",body:"Improving cache hit rates — through longer TTLs, cache key normalization, and aggressive purging on deploy — has more impact on performance than adding more PoPs."},tradeoffs:"Low-latency global delivery and bandwidth cost reduction are the core gains. Cache invalidation is the primary complexity: pushing a bug fix requires both deploying new application code and purging cached responses across all PoPs. Per-PoP configuration drift is also a risk in large CDN setups.",alternatives:"A single-region object store with a CNAME is adequate for static assets when the user base is geographically concentrated. P2P content delivery is effective for very large files (video, software downloads) but has high implementation complexity and limited support for dynamic content.",x:310,y:383,width:250,height:120},{id:"ec-edge-workers",title:"Edge Workers",tooltip:"Serverless compute running at CDN edge",description:"Serverless functions running at CDN edge for personalisation, A/B routing, and auth checks.",rationale:"Some logic — auth cookie validation, A/B test routing, geo-based redirects — must run before the response is served but does not require access to origin infrastructure. Edge workers run at the CDN PoP and execute this logic at the geographic location closest to the user, eliminating a full origin round-trip for trivial decisions.",insight:{label:"Where the scope ends",body:"Edge workers are best for stateless, read-heavy decisions: routing, redirects, auth checks, header manipulation. They are the wrong tool for anything requiring database access, complex state, or heavy compute. Business logic in edge workers creates a debugging burden that rarely justifies the latency savings."},tradeoffs:"Near-zero cold start, no origin round-trip for qualifying requests, and per-request personalisation are the key benefits. The constraints are significant: edge runtimes have limited APIs, execution size limits (1–5 MB in most runtimes), and debugging requires specialized tooling.",alternatives:"Lambda@Edge provides similar capability with wider API support but higher cold-start latency and execution cost. Traditional middleware at origin handles the same use cases without the edge runtime constraints, at the cost of the origin round-trip latency.",x:610,y:203,width:250,height:120},{id:"ec-shield",title:"Origin Shield",tooltip:"Collapses cache-miss requests to origin",description:"Intermediate caching tier that collapses concurrent cache-miss requests to a single origin fetch.",rationale:"A cache miss on a popular asset triggers a request from the CDN PoP to the origin. Under spike traffic, many PoPs may experience simultaneous cache misses for the same asset — a thundering herd. The origin shield collapses these: all PoPs with a miss contact the shield, and only the shield contacts the origin. One origin request instead of dozens.",insight:{label:"Cache miss storms",body:"After a CDN purge, every subsequent request is a cache miss until the cache warms back up. Without a shield, that warming process generates a burst of origin traffic proportional to PoP count times request rate."},tradeoffs:"An 80–95% reduction in origin request volume under cache-miss conditions is the headline benefit. The tradeoff is an additional network hop: requests from a PoP to the shield add a few milliseconds compared to a direct PoP-to-origin path. For latency-sensitive dynamic content, the shield should be bypassed.",alternatives:"No-shield configurations rely on long TTLs and stale-while-revalidate patterns to keep cache hit rates high enough that thundering herds are rare. This works when content changes infrequently. Stale-while-revalidate is often sufficient for non-critical content and simpler to operate.",x:890,y:203,width:250,height:120},{id:"ec-lb",title:"Load Balancer",tooltip:"Distributes requests across app server pool",description:"Layer-7 load balancer distributing origin requests across the application server pool.",rationale:"A single application server cannot serve production traffic for any serious web property — it is both a single point of failure and a capacity ceiling. A load balancer distributes requests across a pool, removes unhealthy instances from rotation, and enables rolling deployments without downtime.",tradeoffs:"Health check-aware routing, SSL termination, and sticky session support are the core capabilities. The load balancer itself requires redundancy — an HA pair or anycast configuration — or it becomes the single point of failure it was meant to eliminate. Capacity planning is critical: a saturated load balancer is as bad as no load balancer.",alternatives:"DNS round-robin is the simplest load distribution mechanism but has no health awareness — a failed server stays in rotation until DNS TTL expires. A service mesh (Envoy, Linkerd) handles L7 routing with more granular traffic control, appropriate when you need fine-grained routing policies beyond simple load distribution.",x:1170,y:203,width:250,height:120},{id:"ec-app",title:"App Servers",tooltip:"Origin application and API fleet",description:"Application server fleet handling dynamic API requests and server-side rendering.",rationale:"Stateless application servers are the correct architecture for horizontally scalable web systems. When a server holds no session state, any request can be handled by any instance — you add capacity by adding instances and remove it by terminating them. This is the foundation of elastic scaling.",insight:{label:"Stateless, defined",body:"Stateless is not the same as memoryless. Stateless means the server does not own state between requests — state lives in the database, cache, or session store. In-process caching and connection pooling are fine; sticky sessions and local file storage are not."},tradeoffs:"Horizontal scaling, simple deployment automation, and instance replaceability are the core benefits. Scale-out cold-start (new instances need time to warm connection pools and in-process caches) is a real concern under sudden traffic spikes. Session affinity complications arise if any in-process state is unavoidable.",alternatives:"Serverless functions (Lambda, Cloud Functions) eliminate the server fleet and scale to zero, removing idle capacity cost. The tradeoff is cold-start latency and execution duration limits. Container-based auto-scaling (ECS, GKE) is the middle ground — containers for density, a managed service for scaling automation.",x:1450,y:203,width:250,height:120},{id:"ec-object",title:"Object Store",tooltip:"Durable storage for static assets and media",description:"Durable object storage (S3 / GCS) for static assets, media files, and build artefacts.",rationale:"Static assets (JS bundles, CSS, images, videos) do not belong on application servers. Object storage provides eleven nines of durability, infinite capacity, per-object ACLs, and native CDN integration for cache fill. It decouples asset serving from application deployment — a frontend release does not touch the application server fleet.",tradeoffs:"Extreme durability, cost-effective at any scale, and native CDN integration are the clear advantages. Egress cost for high-traffic assets can be significant if not routed through CDN. S3 provides strong read-after-write consistency for new objects, but overwrite consistency on existing keys requires care in cache invalidation flows.",alternatives:"An NFS or shared filesystem works for small-scale deployments where assets change frequently and CDN integration is not needed, but does not scale horizontally and is a single point of failure. A dedicated media CDN (Cloudinary, Cloudflare Images) adds transformation and optimization capabilities on top of object storage, appropriate when image processing is a product requirement.",x:1450,y:383,width:250,height:120}],edges:[{id:"e-e1",from:"ec-browser-right",to:"ec-waf-left",label:"all requests"},{id:"e-e2",from:"ec-waf-bottom",to:"ec-cdn-top",label:"clean traffic"},{id:"e-e3",from:"ec-cdn-right",to:"ec-edge-workers-left",label:"cache miss"},{id:"e-e4",from:"ec-cdn-right",to:"ec-object-left",label:"asset fetch"},{id:"e-e5",from:"ec-edge-workers-right",to:"ec-shield-left",label:"dynamic"},{id:"e-e6",from:"ec-shield-right",to:"ec-lb-left",label:"shield pass"},{id:"e-e7",from:"ec-lb-right",to:"ec-app-left",label:"route"},{id:"e-e8",from:"ec-app-bottom",to:"ec-object-top",label:"assets"},{id:"e-e9",from:"ec-object-left",to:"ec-cdn-right",label:"cache fill"}]}]}}]);